package org.eclipse.rdf4j.sail.base;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Compare;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinStatsProvider;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.PatternKey;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class SketchBasedJoinEstimatorLearnedFilterRatioTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	private StubSailStore sailStore;
	private SketchBasedJoinEstimator estimator;
	private IRI follows;
	private IRI name;

	@BeforeEach
	void setUp() {
		sailStore = new StubSailStore();
		estimator = new SketchBasedJoinEstimator(sailStore, 128, 1, 0);
		follows = VF.createIRI("urn:test:follows");
		name = VF.createIRI("urn:test:name");
		loadData(24);
		estimator.rebuildOnceSlow();
	}

	@Test
	void prefersConditionRatioOverPatternRatio() {
		StatementPattern pattern = new StatementPattern(Var.of("s"), Var.of("p", name), Var.of("o"));
		Filter filter = nonSimpleFilter(pattern.clone(), "o", 5);
		double base = estimator.cardinality(alwaysTrueFilter(pattern.clone()));

		estimator.setLearnedStatsProvider(new FixedFilterRatioStatsProvider(true, 0.25d, 0.75d));
		double adjusted = estimator.cardinality(filter);

		assertApprox(base * 0.25d, adjusted);
	}

	@Test
	void fallsBackToPatternRatioWhenConditionRatioMissing() {
		StatementPattern pattern = new StatementPattern(Var.of("s"), Var.of("p", name), Var.of("o"));
		Filter filter = nonSimpleFilter(pattern.clone(), "o", 5);
		double base = estimator.cardinality(alwaysTrueFilter(pattern.clone()));

		estimator.setLearnedStatsProvider(new FixedFilterRatioStatsProvider(true, -1.0d, 0.60d));
		double adjusted = estimator.cardinality(filter);

		assertApprox(base * 0.60d, adjusted);
	}

	@Test
	void fallsBackToHeuristicRatioWhenLearnedRatioUnavailable() {
		StatementPattern pattern = new StatementPattern(Var.of("s"), Var.of("p", name), Var.of("o"));
		Filter filter = equalityFilter(pattern.clone(), "o", "urn:test:o1");
		double base = estimator.cardinality(alwaysTrueFilter(pattern.clone()));

		estimator.setLearnedStatsProvider(new FixedFilterRatioStatsProvider(false, -1.0d, -1.0d));
		double adjusted = estimator.cardinality(filter);

		assertTrue(adjusted < base);
		assertTrue(adjusted > 0.0d);
	}

	@Test
	void appliesLearnedRatiosToFilterWrappedJoinInputs() {
		StatementPattern leftPattern = new StatementPattern(Var.of("s"), Var.of("p", follows), Var.of("o1"));
		StatementPattern rightPattern = new StatementPattern(Var.of("s"), Var.of("p", name), Var.of("o2"));
		Filter leftFilter = nonSimpleFilter(leftPattern, "o1", 2);
		Filter rightFilter = nonSimpleFilter(rightPattern, "o2", 2);
		Join join = new Join(leftFilter, rightFilter);

		double unadjusted = estimator.cardinality(join);
		estimator.setLearnedStatsProvider(new FixedFilterRatioStatsProvider(true, 0.5d, 0.5d));
		double adjusted = estimator.cardinality(join);

		assertTrue(adjusted < unadjusted);
		assertApprox(unadjusted * 0.25d, adjusted);
	}

	private void loadData(int rows) {
		List<Statement> statements = new ArrayList<>(rows * 2);
		for (int i = 0; i < rows; i++) {
			IRI subject = VF.createIRI("urn:test:s" + i);
			IRI object = VF.createIRI("urn:test:o" + i);
			statements.add(VF.createStatement(subject, follows, object));
			statements.add(VF.createStatement(subject, name, object));
		}
		sailStore.addAll(statements);
	}

	private static Filter alwaysTrueFilter(StatementPattern pattern) {
		return new Filter(pattern, new ValueConstant(VF.createLiteral(true)));
	}

	private static Filter equalityFilter(StatementPattern pattern, String varName, String valueIri) {
		return new Filter(pattern,
				new Compare(Var.of(varName),
						new ValueConstant(VF.createIRI(valueIri)),
						Compare.CompareOp.EQ));
	}

	private static Filter nonSimpleFilter(StatementPattern pattern, String varName, int value) {
		return new Filter(pattern,
				new Compare(Var.of(varName),
						new ValueConstant(VF.createLiteral(value)),
						Compare.CompareOp.GT));
	}

	private static void assertApprox(double expected, double actual) {
		double epsilon = Math.max(1.0d, expected * 0.20d);
		assertEquals(expected, actual, epsilon);
	}

	private static final class FixedFilterRatioStatsProvider implements JoinStatsProvider {
		private final boolean hasStats;
		private final double conditionRatio;
		private final double patternRatio;

		private FixedFilterRatioStatsProvider(boolean hasStats, double conditionRatio, double patternRatio) {
			this.hasStats = hasStats;
			this.conditionRatio = conditionRatio;
			this.patternRatio = patternRatio;
		}

		@Override
		public void reset() {
		}

		@Override
		public void recordCall(PatternKey key) {
		}

		@Override
		public void recordResults(PatternKey key, long resultCount) {
		}

		@Override
		public void seedIfAbsent(PatternKey key, double defaultCardinality, long priorCalls) {
		}

		@Override
		public double getAverageResults(PatternKey key) {
			return 0.0d;
		}

		@Override
		public boolean hasStats(PatternKey key) {
			return hasStats;
		}

		@Override
		public long getTotalCalls() {
			return 0L;
		}

		@Override
		public double getFilterPassRatio(PatternKey key, String filterKey) {
			return conditionRatio;
		}

		@Override
		public double getPatternPassRatio(PatternKey key) {
			return patternRatio;
		}
	}
}
